class TrieNode:
  def __init__(self):
    self.char = ''
    self.count = 0
    self.children = {}

def insert(root, word):
  for i in range(len(word)):
    if word[i] not in root.children:
      root.children[word[i]] = TrieNode()
    root.children[word[i]].count += 1
  return root

